        let systemPrompt = """
        You are an image classifier. Based on the following image description, classify it into one of these categories:
        airplane / automobile / bird / cat / deer / dog / frog / horse / ship / truck
        Output ONLY the category name, nothing else.
        """

        func makeCase(name: String, description: String, label: String, aliases: [String]) -> BenchmarkTestCase {
            BenchmarkTestCase(
                name: name,
                category: .imageClassification,
                prompt: systemPrompt + "\n\nImage description: \(description)",
                qualityRules: [
                    QualityRule(name: "Correct classification", type: .exactClassification, weight: 3, params: [label] + aliases),
                    QualityRule(name: "Concise output", type: .lengthRange, weight: 1, params: ["1", "30"])
                ]
            )
        }

